def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        weighted_sum = 0
        for j in range(1, 15):
            weight = (-1)**j / (j**1.5)
            term = weight * (ratio ** j)
            if j % 3 == 0:
                term *= 1.2
            elif j % 4 == 0:
                term *= 0.85
            weighted_sum += term
        score = abs(weighted_sum)
        remaining = capacity - item
        if remaining < 0:
            score = np.inf
        elif remaining < 0.02 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.5
        elif remaining < 0.3 * capacity:
            score *= 1.1
        else:
            score *= 0.75
        mod_capacity = int(capacity)
        if mod_capacity % 7 == 0:
            score -= 0.07 * (capacity / 8)
        elif mod_capacity % 11 == 0:
            score -= 0.12 * (capacity / 15)
        else:
            score -= 0.03 * (capacity / 50)
        penalty = 0
        for k in range(1, 6):
            dist = abs(capacity - item * k)
            threshold = 0.02 * capacity + 0.005 * k
            if dist < threshold:
                penalty += 0.15 * k + 0.05 * np.sin(k * np.pi / 2)
        factor = 1.0
        if int(item) % 2 == 0 and int(capacity) % 2 == 1:
            factor = 1.3
        elif int(item) % 3 == 0 and int(capacity) % 5 == 0:
            factor = 0.9
        score = (score + penalty) * factor
        if score < 0:
            score = 0
        if i % 2 == 0:
            for l in range(1, 4):
                adjust = (l**2) / (capacity + 1)
                score += adjust * ((-1) ** l)
        priorities[i] = score
    return priorities
